+/// Configuration for ngram speculation
+pub const NgramConfig = struct {
+    /// Number of tokens in the lookup prefix (context window)
+    prefix_len: u32 = 4,
+
+    /// Maximum tokens to speculate ahead
+    max_speculation: u32 = 8,
+
+    /// Minimum times a sequence must appear to be cached
+    min_frequency: u32 = 2,
+
+    /// Maximum cache entries (LRU eviction when full)
+    max_entries: u32 = 10000,
+
+    /// Minimum confidence to use speculation (0.0 - 1.0)
+    min_confidence: f32 = 0.7,
+};
+
+/// A cached ngram entry
+const NgramEntry = struct {
+    /// Continuation tokens after the prefix
+    continuation: []i32,
+
+    /// Number of times this sequence was observed
+    frequency: u32,
+
+    /// Last access time for LRU
+    last_access: i64,
+
+    /// How often the speculation was accepted vs rejected
+    accept_count: u32,
+    reject_count: u32,
+
+    fn confidence(self: *const NgramEntry) f32 {
+        const total = self.accept_count + self.reject_count;
+        if (total == 0) return 1.0; // Assume good until proven otherwise
+        return @as(f32, @floatFromInt(self.accept_count)) / @as(f32, @floatFromInt(total));
     }
